import{_ as e,c as l,o,ae as i}from"./chunks/framework.CLNW5JS9.js";const h=JSON.parse('{"title":"Windows系统下虚拟机Ubuntu安装OpenClaw详细部署说明文档","description":"","frontmatter":{},"headers":[],"relativePath":"ai/wsl-openclaw.md","filePath":"ai/wsl-openclaw.md"}'),t={name:"ai/wsl-openclaw.md"};function p(n,a,r,d,u,s){return o(),l("div",null,a[0]||(a[0]=[i('<h1 id="windows系统下虚拟机ubuntu安装openclaw详细部署说明文档" tabindex="-1">Windows系统下虚拟机Ubuntu安装OpenClaw详细部署说明文档 <a class="header-anchor" href="#windows系统下虚拟机ubuntu安装openclaw详细部署说明文档" aria-label="Permalink to &quot;Windows系统下虚拟机Ubuntu安装OpenClaw详细部署说明文档&quot;">​</a></h1><h2 id="一、文档概述" tabindex="-1">一、文档概述 <a class="header-anchor" href="#一、文档概述" aria-label="Permalink to &quot;一、文档概述&quot;">​</a></h2><h3 id="_1-1-文档目的" tabindex="-1">1.1 文档目的 <a class="header-anchor" href="#_1-1-文档目的" aria-label="Permalink to &quot;1.1 文档目的&quot;">​</a></h3><p>本文档详细描述在Windows操作系统中，通过VMware Workstation搭建Ubuntu虚拟机，并在虚拟机内完成OpenClaw的安装、配置与验证的全流程，适用于零基础用户，每一步均提供具体操作指引、命令说明及常见问题解决方案，确保部署过程可复现、无遗漏。</p><h3 id="_1-2-适用环境" tabindex="-1">1.2 适用环境 <a class="header-anchor" href="#_1-2-适用环境" aria-label="Permalink to &quot;1.2 适用环境&quot;">​</a></h3><ul><li><p>主机系统：Windows 10/11（64位，建议专业版）</p></li><li><p>虚拟机软件：VMware Workstation 17（推荐17.5及以上版本，兼容性更好）</p></li><li><p>Ubuntu系统：Ubuntu 24.04 LTS（长期支持版，稳定性强，适配OpenClaw所有版本）</p></li><li><p>OpenClaw版本：最新稳定版（文档将采用官方推荐的一键安装方式，自动适配最新版本）</p></li></ul><h3 id="_1-3-硬件要求" tabindex="-1">1.3 硬件要求 <a class="header-anchor" href="#_1-3-硬件要求" aria-label="Permalink to &quot;1.3 硬件要求&quot;">​</a></h3><p>为确保虚拟机及OpenClaw正常运行，主机硬件需满足以下最低要求，推荐配置可提升运行流畅度：</p><table tabindex="0"><thead><tr><th>硬件类型</th><th>最低要求</th><th>推荐要求</th></tr></thead><tbody><tr><td>处理器</td><td>双核及以上，支持虚拟化技术（VT-x/AMD-V）</td><td>四核及以上，Intel i5/i7或AMD Ryzen 5/7</td></tr><tr><td>内存（RAM）</td><td>4GB空闲内存（主机总内存≥8GB）</td><td>8GB空闲内存（主机总内存≥16GB）</td></tr><tr><td>存储空间</td><td>至少25GB可用磁盘空间（建议非C盘）</td><td>50GB及以上可用磁盘空间（SSD优先，提升读写速度）</td></tr><tr><td>网络</td><td>稳定的有线/无线网络（用于下载系统镜像、软件依赖）</td><td>高速网络（加速镜像及依赖包下载）</td></tr></tbody></table><h3 id="_1-4-前置准备" tabindex="-1">1.4 前置准备 <a class="header-anchor" href="#_1-4-前置准备" aria-label="Permalink to &quot;1.4 前置准备&quot;">​</a></h3><p>部署前需提前下载以下工具及镜像，建议保存至非C盘（如D盘“部署工具”文件夹），避免后续操作中磁盘空间不足：</p><ul><li><p>VMware Workstation 17安装包：可从<a href="https://www.vmware.com/" target="_blank" rel="noreferrer">VMware官方网站</a>下载，或参考文档提供的可靠链接（二选一即可，如17.5或17.6版本）</p></li><li><p>Ubuntu 24.04 LTS镜像文件（ISO格式）：从Ubuntu官方网站下载，无需解压，直接用于虚拟机安装；</p></li><li><p>管理员权限：Windows主机需拥有管理员权限，用于安装VMware及启用虚拟化功能；</p></li><li><p>网络通畅：确保主机可正常访问互联网，用于下载Ubuntu系统更新、OpenClaw及相关依赖。</p></li></ul><h2 id="二、windows主机安装vmware-workstation" tabindex="-1">二、Windows主机安装VMware Workstation <a class="header-anchor" href="#二、windows主机安装vmware-workstation" aria-label="Permalink to &quot;二、Windows主机安装VMware Workstation&quot;">​</a></h2><h3 id="_2-1-安装步骤" tabindex="-1">2.1 安装步骤 <a class="header-anchor" href="#_2-1-安装步骤" aria-label="Permalink to &quot;2.1 安装步骤&quot;">​</a></h3><ol><li><p>双击下载的VMware Workstation安装包，弹出安装向导，点击“下一步”；</p></li><li><p>勾选“我接受许可协议中的条款”，点击“下一步”；</p></li><li><p>选择安装路径（建议修改为非C盘，如D:\\Program Files\\VMware），取消勾选“启动时检查产品更新”（可后续手动更新），点击“下一步”；</p></li><li><p>取消勾选“创建桌面快捷方式”“创建开始菜单快捷方式”（可选，根据个人习惯），点击“下一步”；</p></li><li><p>点击“安装”，等待安装完成（约5-10分钟，取决于主机性能）；</p></li><li><p>安装完成后，弹出激活界面，可输入激活密钥（自行获取），或选择“试用30天”，点击“完成”；</p></li><li><p>启动VMware Workstation，确认软件正常打开，无报错即可进入下一步。</p></li></ol><h3 id="_2-2-启用主机虚拟化功能-关键步骤" tabindex="-1">2.2 启用主机虚拟化功能（关键步骤） <a class="header-anchor" href="#_2-2-启用主机虚拟化功能-关键步骤" aria-label="Permalink to &quot;2.2 启用主机虚拟化功能（关键步骤）&quot;">​</a></h3><p>若启动VMware后提示“无法启用虚拟化”，需先在主机BIOS中启用虚拟化功能，操作步骤如下：</p><ol><li><p>关闭Windows主机，重启电脑；</p></li><li><p>开机时立即多次按快捷键（不同品牌电脑不同，常见F2、Delete、F10），进入BIOS界面；</p></li><li><p>在BIOS中找到“Virtualization”“VT-x”或“SVM”选项（通常在“Advanced”“CPU Configuration”菜单下）；</p></li><li><p>将该选项设置为“Enabled”（启用），按快捷键保存并退出BIOS（通常为F10）；</p></li><li><p>重启电脑，再次启动VMware，即可正常使用虚拟化功能。</p></li></ol><h3 id="_2-3-常见问题" tabindex="-1">2.3 常见问题 <a class="header-anchor" href="#_2-3-常见问题" aria-label="Permalink to &quot;2.3 常见问题&quot;">​</a></h3><ul><li><p>问题1：安装VMware时提示“缺少.NET Framework”？ 解决方案：下载并安装对应版本的.NET Framework（可从微软官网下载），重启电脑后重新安装VMware。</p></li><li><p>问题2：BIOS中找不到虚拟化选项？ 解决方案：确认主机处理器支持虚拟化技术（大部分2018年后的电脑均支持），若仍找不到，可查询电脑品牌的BIOS操作手册，或联系厂商客服。</p></li></ul><h2 id="三、vmware中创建并安装ubuntu虚拟机" tabindex="-1">三、VMware中创建并安装Ubuntu虚拟机 <a class="header-anchor" href="#三、vmware中创建并安装ubuntu虚拟机" aria-label="Permalink to &quot;三、VMware中创建并安装Ubuntu虚拟机&quot;">​</a></h2><h3 id="_3-1-创建虚拟机" tabindex="-1">3.1 创建虚拟机 <a class="header-anchor" href="#_3-1-创建虚拟机" aria-label="Permalink to &quot;3.1 创建虚拟机&quot;">​</a></h3><ol><li><p>启动VMware Workstation，点击主界面“创建新虚拟机”，或通过“文件→新建虚拟机”进入向导；</p></li><li><p>在弹出的向导中，选择“典型（推荐）”选项，点击“下一步”；</p></li><li><p>选择“安装程序光盘镜像文件（ISO）”，点击“浏览”，找到提前下载的<a href="https://ubuntu.com/download/desktop" target="_blank" rel="noreferrer">Ubuntu 2</a><a href="https://ubuntu.com/download/desktop" target="_blank" rel="noreferrer">4</a><a href="https://ubuntu.com/download/desktop" target="_blank" rel="noreferrer">.04 LTS ISO镜像文件</a>，点击“下一步”；</p></li><li><p>VMware会自动识别Ubuntu系统，无需手动选择系统类型，直接进入个性化设置界面：</p></li></ol><ul><li>全名：输入英文名或拼音（如“ZhangWei”，禁止使用中文、空格及特殊符号）；</li><li>用户名：输入小写英文字母（如“zhangwei”，将作为Ubuntu登录用户名）；</li><li>密码：设置易记且不易破解的密码（如“Ubuntu123!”）；</li><li>确认密码：再次输入相同密码； 填写完成后点击“下一步”。</li></ul><ol><li><p>命名虚拟机（如“Ubuntu-OpenClaw”），选择虚拟机文件保存路径（建议非C盘，如D:\\VMware\\Ubuntu-OpenClaw），点击“下一步”；</p></li><li><p>设置虚拟磁盘大小：基础使用建议25-30GB，若需深度使用或安装更多依赖，建议40-60GB，保持默认的“将虚拟磁盘存储为单个文件”，点击“下一步”；</p></li><li><p>在概要页面确认所有设置无误，点击“完成”，虚拟机开始创建并自动启动，进入Ubuntu安装流程。</p></li></ol><h3 id="_3-2-安装ubuntu系统" tabindex="-1">3.2 安装Ubuntu系统 <a class="header-anchor" href="#_3-2-安装ubuntu系统" aria-label="Permalink to &quot;3.2 安装Ubuntu系统&quot;">​</a></h3><p>虚拟机启动后，会自动进入Ubuntu安装界面，按以下步骤操作：</p><ol><li><p>选择安装语言：默认“Chinese”，点击“Install Ubuntu”；</p></li><li><p>选择键盘布局：默认“汉语)”，点击“Continue”；</p></li><li><p>提示更新可用，选择跳过</p></li><li><p>选择安装类型：交互式安装，包含图形界面及常用工具，点击“Continue”；</p></li><li><p>磁盘分区：默认“Erase disk and install Ubuntu”（擦除虚拟磁盘并安装，仅针对虚拟机磁盘，不影响主机），点击“Install Now”，弹出确认提示，点击“Continue”；</p></li><li><p>确认用户信息：自动填充之前设置的全名、用户名及密码，无需修改，点击“Continue”；</p></li><li><p>选择时区：在地图上点击“Shanghai”（或搜索“Shanghai”），确认时区为“Asia/Shanghai”，点击“Continue”；</p></li><li><p>开始安装：系统自动完成安装流程，期间会下载系统更新及依赖，耗时约15-25分钟（取决于网络速度和主机性能）；</p></li><li><p>安装完成后，弹出提示“Please restart now”，点击“Restart Now”，虚拟机重启，重启时会提示“Please remove the installation medium”，无需操作，直接按Enter键即可；</p></li><li><p>重启后，进入Ubuntu登录界面，输入之前设置的密码，登录系统，至此Ubuntu虚拟机安装完成。</p></li></ol><h3 id="_3-3-虚拟机优化配置-选做" tabindex="-1">3.3 虚拟机优化配置（选做） <a class="header-anchor" href="#_3-3-虚拟机优化配置-选做" aria-label="Permalink to &quot;3.3 虚拟机优化配置（选做）&quot;">​</a></h3><p>为提升虚拟机使用体验，解决屏幕分辨率、鼠标切换、文件共享等问题，需完成以下优化配置：</p><h4 id="_3-3-1-安装vmware增强工具" tabindex="-1">3.3.1 安装VMware增强工具 <a class="header-anchor" href="#_3-3-1-安装vmware增强工具" aria-label="Permalink to &quot;3.3.1 安装VMware增强工具&quot;">​</a></h4><ol><li><p>在VMware菜单栏点击“虚拟机→安装VMware Tools”；</p></li><li><p>Ubuntu桌面会出现一个挂载的光盘图标，双击打开，找到里面的VMware Tools安装包（.tar.gz格式）；</p></li><li><p>右键点击安装包，选择“提取到…”，将其解压到桌面；</p></li><li><p>打开终端（按快捷键Ctrl+Alt+T），输入以下命令进入解压后的目录（替换“vmware-tools-distrib”为实际解压文件夹名称）： <code>cd 桌面/vmware-tools-distrib/</code></p></li><li><p>执行安装命令（添加-d参数可使用默认设置，无需手动确认）： <code>sudo ./vmware-install.pl -d</code></p></li><li><p>安装完成后，输入命令重启虚拟机： <code>sudo reboot</code></p></li><li><p>重启后，虚拟机分辨率会自动适配主机屏幕，鼠标可无缝在主机与虚拟机之间切换，剪贴板共享功能也会生效。</p></li></ol><h4 id="_3-3-2-更新系统及安装基础工具" tabindex="-1">3.3.2 更新系统及安装基础工具 <a class="header-anchor" href="#_3-3-2-更新系统及安装基础工具" aria-label="Permalink to &quot;3.3.2 更新系统及安装基础工具&quot;">​</a></h4><p>新安装的Ubuntu系统需更新软件包，避免依赖冲突，同时安装后续OpenClaw所需的基础工具：</p><ol><li><p>打开终端，输入以下命令更新系统包列表： <code>sudo apt update &amp;&amp; sudo apt upgrade -y</code></p></li><li><p>安装基础工具链（git、curl等，OpenClaw安装必需）： <code>sudo apt install -y curl wget git build-essential</code></p></li><li><p>等待命令执行完成，若出现提示“是否继续”，按Enter键确认即可。</p></li></ol><h4 id="_3-3-3-配置中文输入法-可选" tabindex="-1">3.3.3 配置中文输入法（可选） <a class="header-anchor" href="#_3-3-3-配置中文输入法-可选" aria-label="Permalink to &quot;3.3.3 配置中文输入法（可选）&quot;">​</a></h4><p>若需要在Ubuntu中使用中文输入，可按以下步骤配置：</p><ol><li><p>在终端输入命令安装中文输入法相关包： <code>sudo apt install fcitx5 fcitx5-chinese-addons -y</code></p></li><li><p>打开“设置→区域和语言→输入源”，点击“+”号，添加中文输入法；</p></li><li><p>重启虚拟机，按Ctrl+空格即可切换中英文输入法。</p></li></ol><h4 id="_3-3-4-配置主机与虚拟机文件共享-可选" tabindex="-1">3.3.4 配置主机与虚拟机文件共享（可选） <a class="header-anchor" href="#_3-3-4-配置主机与虚拟机文件共享-可选" aria-label="Permalink to &quot;3.3.4 配置主机与虚拟机文件共享（可选）&quot;">​</a></h4><p>为方便在主机与虚拟机之间传输文件，可通过VMware共享文件夹功能实现，步骤如下：</p><ol><li><p>关闭Ubuntu虚拟机，在VMware中右键点击该虚拟机，选择“设置→选项→共享文件夹”；</p></li><li><p>点击“添加”，选择主机上的文件夹（如D:\\VMware\\Share）作为共享目录，勾选“启动共享”，点击“完成”；</p></li><li><p>在“共享文件夹”界面选择“总是启用”，点击“确定”；</p></li><li><p>启动虚拟机，在Ubuntu中进入“/mnt/hgfs”目录，即可看到共享文件夹，实现主机与虚拟机文件互传。</p></li></ol><h3 id="_3-4-常见问题" tabindex="-1">3.4 常见问题 <a class="header-anchor" href="#_3-4-常见问题" aria-label="Permalink to &quot;3.4 常见问题&quot;">​</a></h3><ul><li><p>问题1：Ubuntu安装时卡在“Download updates”界面？ 解决方案：取消勾选“Download updates while installing Ubuntu”，先完成安装，后续再手动更新系统。</p></li><li><p>问题2：虚拟机屏幕太小，分辨率无法调整？ 解决方案：确认VMware增强工具已正确安装，若未安装或安装失败，重新执行3.3.1步骤；若已安装仍有问题，输入命令： <code>sudo apt install open-vm-tools-desktop -y &amp;&amp; sudo reboot</code>。</p></li><li><p>问题3：Ubuntu无法上网？ 解决方案：在VMware中选择“编辑→虚拟网络编辑器”，确保NAT模式已启用；在Ubuntu终端输入以下命令修复DNS： <code>echo &quot;nameserver 8.8.8.8&quot; | sudo tee /etc/resolv.conf &amp;&amp; sudo service network-manager restart</code>。</p></li></ul><h2 id="四、ubuntu虚拟机中安装openclaw" tabindex="-1">四、Ubuntu虚拟机中安装OpenClaw <a class="header-anchor" href="#四、ubuntu虚拟机中安装openclaw" aria-label="Permalink to &quot;四、Ubuntu虚拟机中安装OpenClaw&quot;">​</a></h2><p>OpenClaw提供三种主流安装方式：一键脚本安装（最推荐，适合新手）、Docker安装（适合环境隔离）、源码安装（适合开发者），本文重点介绍一键脚本安装方式，兼顾便捷性和稳定性，同时简要说明其他两种方式的操作流程。</p><h3 id="_4-1-安装前准备" tabindex="-1">4.1 安装前准备 <a class="header-anchor" href="#_4-1-安装前准备" aria-label="Permalink to &quot;4.1 安装前准备&quot;">​</a></h3><ol><li><p>确认Ubuntu虚拟机已联网，可通过终端输入以下命令测试网络连通性： <code>ping www.baidu.com</code>，若能正常接收数据包，说明网络正常；</p></li><li><p>确认已完成3.3.2步骤的系统更新及基础工具安装，避免依赖缺失；</p></li><li><p>（可选）若需使用AI模型功能，提前获取对应AI供应商的API密钥（如OpenAI、Anthropic等），后续配置时需用到。</p></li></ol><h3 id="_4-2-一键脚本安装-最推荐" tabindex="-1">4.2 一键脚本安装（最推荐） <a class="header-anchor" href="#_4-2-一键脚本安装-最推荐" aria-label="Permalink to &quot;4.2 一键脚本安装（最推荐）&quot;">​</a></h3><p>这是官方推荐的最简单方式，脚本会自动处理Node.js依赖的检测、安装，以及OpenClaw的部署，无需手动配置，步骤如下：</p><ol><li><p>打开Ubuntu终端（Ctrl+Alt+T）；</p></li><li><p>输入以下一键安装命令，按Enter键执行： <code>curl -fsSL https://openclaw.ai/install.sh | bash</code></p></li><li><p>脚本执行过程中，会自动下载Node.js（22+版本，OpenClaw必需）及OpenClaw相关依赖，耗时约5-10分钟（取决于网络速度）；</p></li><li><p>若出现“Permission denied”（权限不足）提示，在命令前添加sudo： <code>sudo curl -fsSL https://openclaw.ai/install.sh | bash</code></p></li><li><p>等待脚本执行完成，若提示“OpenClaw installed successfully”，说明安装成功。</p></li></ol><h3 id="_4-3-docker安装-环境隔离-可选" tabindex="-1">4.3 Docker安装（环境隔离，可选） <a class="header-anchor" href="#_4-3-docker安装-环境隔离-可选" aria-label="Permalink to &quot;4.3 Docker安装（环境隔离，可选）&quot;">​</a></h3><p>若偏好使用Docker实现环境隔离，避免影响Ubuntu系统原有配置，可按以下步骤操作：</p><ol><li><p>安装Docker及Docker Compose（若未安装）： <code>sudo apt install -y docker.io docker-compose</code></p></li><li><p>启动Docker服务并设置开机自启： <code>sudo systemctl start docker &amp;&amp; sudo systemctl enable docker</code></p></li><li><p>创建并进入OpenClaw项目目录： <code>mkdir -p ~/openclaw &amp;&amp; cd ~/openclaw</code></p></li><li><p>克隆OpenClaw官方仓库： <code>git clone https://github.com/openclaw/openclaw.git .</code></p></li><li><p>运行Docker设置脚本，自动构建镜像、生成访问令牌并启动服务： <code>./docker-setup.sh</code></p></li><li><p>脚本执行完成后，Docker容器会自动启动，OpenClaw部署完成。</p></li></ol><h3 id="_4-4-源码安装-开发者-可选" tabindex="-1">4.4 源码安装（开发者，可选） <a class="header-anchor" href="#_4-4-源码安装-开发者-可选" aria-label="Permalink to &quot;4.4 源码安装（开发者，可选）&quot;">​</a></h3><p>若需修改OpenClaw源码，可选择从源码编译安装，步骤如下：</p><ol><li><p>安装Node.js 22+（若未安装）： <code>curl -fsSL https://deb.nodesource.com/setup_22.x | sudo -E bash &amp;&amp; sudo apt install -y nodejs</code></p></li><li><p>验证Node.js版本： <code>node --version</code>，需显示v22.x.x；</p></li><li><p>克隆OpenClaw官方仓库： <code>git clone https://github.com/openclaw/openclaw.git</code></p></li><li><p>进入仓库目录并安装依赖、编译源码： <code>cd openclaw &amp;&amp; npm install &amp;&amp; npm run build</code></p></li><li><p>编译完成后，即可启动OpenClaw。</p></li></ol><h2 id="五、openclaw初始化配置与验证" tabindex="-1">五、OpenClaw初始化配置与验证 <a class="header-anchor" href="#五、openclaw初始化配置与验证" aria-label="Permalink to &quot;五、OpenClaw初始化配置与验证&quot;">​</a></h2><h3 id="_5-1-初始化配置" tabindex="-1">5.1 初始化配置 <a class="header-anchor" href="#_5-1-初始化配置" aria-label="Permalink to &quot;5.1 初始化配置&quot;">​</a></h3><p>安装完成后，需通过交互式向导完成OpenClaw的核心配置，包括AI模型选择、API密钥配置等，步骤如下：</p><ol><li><p>打开终端，输入以下命令启动配置向导： <code>openclaw onboard --install-daemon</code></p></li><li><p>按照向导提示逐步操作： ① 选择AI模型提供商：根据自身需求选择（如OpenAI、Anthropic、阿里云百炼等）； ② 输入API密钥：粘贴提前获取的对应AI供应商的API密钥（密钥仅存储在本地，不发送至第三方）； ③ 配置网关守护进程：确认安装，该进程可让OpenClaw在后台持续运行，并支持开机自启； ④ 设置工作区路径：默认路径为~/.openclaw/workspace，用于存储配置和数据，无需修改，直接确认；</p></li><li><p>配置完成后，向导会提示“Configuration completed successfully”，表示初始化完成。</p></li></ol><p>注：若使用Docker安装，docker-setup.sh脚本会自动启动配置向导，无需手动执行上述命令。</p><h3 id="_5-2-验证安装" tabindex="-1">5.2 验证安装 <a class="header-anchor" href="#_5-2-验证安装" aria-label="Permalink to &quot;5.2 验证安装&quot;">​</a></h3><p>配置完成后，需验证OpenClaw是否正常运行，步骤如下：</p><ol><li><p>检查OpenClaw版本，确认安装成功： <code>openclaw --version</code>，若能显示版本号（如v2026.3.2），说明安装正常；</p></li><li><p>检查网关状态，确认守护进程正常运行： <code>openclaw gateway status</code>，若显示“running”，说明网关已启动；</p></li><li><p>获取访问令牌（用于登录Web界面）： <code>grep -A1 &#39;&quot;token&quot;&#39; ~/.openclaw/openclaw.json</code>，复制输出的令牌内容；</p></li><li><p>访问Web UI：打开Ubuntu自带的浏览器，输入地址<code>http://127.0.0.1:18789</code>，粘贴获取的令牌，点击登录；</p></li><li><p>登录成功后，进入OpenClaw控制面板，可尝试发送测试消息（如“你能做什么？”），若能正常回复，说明OpenClaw完全部署成功。</p></li></ol><h3 id="_5-3-额外配置-可选" tabindex="-1">5.3 额外配置（可选） <a class="header-anchor" href="#_5-3-额外配置-可选" aria-label="Permalink to &quot;5.3 额外配置（可选）&quot;">​</a></h3><h4 id="_5-3-1-局域网访问配置" tabindex="-1">5.3.1 局域网访问配置 <a class="header-anchor" href="#_5-3-1-局域网访问配置" aria-label="Permalink to &quot;5.3.1 局域网访问配置&quot;">​</a></h4><p>若需在主机或局域网内其他设备访问Ubuntu虚拟机中的OpenClaw Web界面，需修改配置，让其监听所有网络接口：</p><div class="language-Plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">Plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>openclaw config set gateway.bind lan &amp;&amp; openclaw gateway restart</span></span></code></pre></div><p>修改后，可通过“Ubuntu虚拟机IP地址:18789”访问Web界面（虚拟机IP可通过<code>ifconfig</code>命令查询）。</p><h4 id="_5-3-2-开机自启配置" tabindex="-1">5.3.2 开机自启配置 <a class="header-anchor" href="#_5-3-2-开机自启配置" aria-label="Permalink to &quot;5.3.2 开机自启配置&quot;">​</a></h4><p>若希望Ubuntu重启后，OpenClaw自动启动，可执行以下命令： <code>sudo systemctl enable openclaw</code></p><h3 id="_5-4-常见问题" tabindex="-1">5.4 常见问题 <a class="header-anchor" href="#_5-4-常见问题" aria-label="Permalink to &quot;5.4 常见问题&quot;">​</a></h3><ul><li><p>问题1：执行openclaw命令提示“command not found”？ 解决方案：确认OpenClaw安装成功，若未成功，重新执行一键安装命令；若已安装，重启终端后再次尝试。</p></li><li><p>问题2：网关状态显示“stopped”，无法启动？ 解决方案：检查Node.js版本是否为22+，若版本过低，重新安装Node.js；执行命令<code>openclaw gateway start</code>手动启动网关。</p></li><li><p>问题3：Web界面无法访问？ 解决方案：确认网关已启动，检查Ubuntu防火墙是否关闭（执行<code>sudo ufw disable</code>关闭防火墙）；若为局域网访问，确认虚拟机IP地址正确，且主机与虚拟机网络互通。</p></li></ul><h2 id="六、后续操作与维护" tabindex="-1">六、后续操作与维护 <a class="header-anchor" href="#六、后续操作与维护" aria-label="Permalink to &quot;六、后续操作与维护&quot;">​</a></h2><h3 id="_6-1-openclaw升级" tabindex="-1">6.1 OpenClaw升级 <a class="header-anchor" href="#_6-1-openclaw升级" aria-label="Permalink to &quot;6.1 OpenClaw升级&quot;">​</a></h3><p>为获取最新功能和安全补丁，可定期升级OpenClaw，根据安装方式选择对应命令：</p><ul><li><p>一键脚本/ npm安装： <code>npm update -g openclaw@latest</code></p></li><li><p>Docker安装： <code>docker pull openclaw/openclaw:latest &amp;&amp; docker restart openclaw</code></p></li><li><p>源码安装： <code>cd openclaw &amp;&amp; git pull &amp;&amp; npm install &amp;&amp; npm run build</code></p></li></ul><h3 id="_6-2-虚拟机备份与恢复" tabindex="-1">6.2 虚拟机备份与恢复 <a class="header-anchor" href="#_6-2-虚拟机备份与恢复" aria-label="Permalink to &quot;6.2 虚拟机备份与恢复&quot;">​</a></h3><p>为避免部署环境丢失，可定期备份虚拟机：</p><ol><li><p>关闭Ubuntu虚拟机；</p></li><li><p>在VMware中右键点击该虚拟机，选择“管理→克隆”，按照向导完成克隆（备份）；</p></li><li><p>若需恢复，直接打开克隆后的虚拟机文件即可。</p></li></ol><h3 id="_6-3-常见故障排查" tabindex="-1">6.3 常见故障排查 <a class="header-anchor" href="#_6-3-常见故障排查" aria-label="Permalink to &quot;6.3 常见故障排查&quot;">​</a></h3><ul><li><p>故障1：OpenClaw无法调用AI模型，提示“API Key错误”？ 解决方案：检查API密钥是否正确，确认密钥未过期，重新在配置向导中输入密钥。</p></li><li><p>故障2：虚拟机运行卡顿？ 解决方案：关闭虚拟机，在VMware中右键点击虚拟机→“设置”，增加内存（至少4GB）和处理器核心数（至少2核），若有条件，将虚拟磁盘迁移到SSD。</p></li><li><p>故障3：OpenClaw启动失败，提示依赖缺失？ 解决方案：重新执行系统更新命令<code>sudo apt update &amp;&amp; sudo apt upgrade -y</code>，然后重新安装OpenClaw。</p></li></ul><h2 id="七、总结" tabindex="-1">七、总结 <a class="header-anchor" href="#七、总结" aria-label="Permalink to &quot;七、总结&quot;">​</a></h2><p>本文档完整覆盖了“Windows主机安装VMware→创建并配置Ubuntu虚拟机→安装OpenClaw→初始化配置与验证”的全流程，重点推荐新手使用一键脚本安装OpenClaw，操作简单、不易出错。部署过程中，若遇到问题，可参考各章节的常见问题解决方案，或查阅OpenClaw官方文档（<a href="https://openclaws.io/zh/install/%EF%BC%89%E8%8E%B7%E5%8F%96%E6%9B%B4%E5%A4%9A%E5%B8%AE%E5%8A%A9%E3%80%82" target="_blank" rel="noreferrer">https://openclaws.io/zh/install/）获取更多帮助。</a></p><p>完成部署后，可根据自身需求，配置AI模型、局域网访问等功能，充分发挥OpenClaw的作用。</p>',85)]))}const w=e(t,[["render",p]]);export{h as __pageData,w as default};
